  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.Attributes;
  import org.apache.log4j.Logger; 
  import java.util.Date;
  import sailpoint.object.Custom;
  import java.util.Map;
  import java.text.SimpleDateFormat;


  String strType="";
  String strRehireAction="";
  String strRehireActionReason=null;  
  String strEffectiveDate = null;
  String strAction="";
  String strPerOrg=null;
  String strUsrName=null;
  String strActionReason=null;
  String strManager=null;
  Date effectiveDate=null;
  Date currentDate=null;
  String strCurrentDate=null;
  long dayDiff=0;

  Logger logger = Logger.getLogger("com.CustomLogs");

 logger.debug("Entering  Ascension-Rule-PrimaryDb-Customization-Rule");
 
 String logName = "rule.Ascension-Rule-PrimaryDb-Customization-Rule";
String custObjName = "Ascension-Custom-Ministry_EMP_CLASS_ExclusionList";
String ministryKey = "ILARL";
boolean exclusion = false;
  
  public boolean checkExclusion(Custom customObject, String ministryKey, String empClass){

    boolean exclusionFlag = false;
    debug(logName,"Data"+customObject+", "+ministryKey+", "+empClass);
    // Retrieve Attributes from Custom object
    Attributes attributes = customObject.getAttributes();

    // Check if Ministry_EMP_CLASS_ExclusionList exists
    if (attributes.containsKey("Ministry_EMP_CLASS_ExclusionList")) {
      Map exclusionMap = attributes.get("Ministry_EMP_CLASS_ExclusionList");

      // Check if the specified ministryKey (like "ILARL") exists in the exclusionMap
      if (exclusionMap.containsKey(ministryKey)) {
        List empClassList = exclusionMap.get(ministryKey);
        debug(logName,"emp class list "+empClassList);
        // Check if the empClass (like "C24") exists in the list
        if (empClassList.contains(empClass)) {
          exclusionFlag = true;
        }
      }
    }
    debug(logName,"Ex flag"+exclusionFlag);
    return exclusionFlag;
  }
  
  public String CheckDate(String effDate, String CurrentDate){
    SimpleDateFormat sdf = new SimpleDateFormat("MM/dd/yyyy");  
    todaysDate = sdf.parse(CurrentDate);         
    log.error("todaysDate= "+todaysDate);

    if(effDate != null){

      Date effectiveDate = sdf.parse(effDate);
      logger.debug("effectiveDate= "+effectiveDate);          

      //For Future-hire
      if(effectiveDate.after(todaysDate)){ 
        return "futureDate";
      }	
      if(effectiveDate.equals(todaysDate)){ 
        return "currentDate";
      }
      if(effectiveDate.before(todaysDate)){ 
        return "pastDate";
      }		

    }
  }

  try{
    logger.debug("Inside Ascension-Rule-PrimaryDb-Customization-Rule - START");  
    logger.debug("strUsrName= "+strUsrName);
    Attributes attributes = object.getAttributes();   
    strUsrName = object.getStringAttribute("EMPLID");          
    strPerOrg = object.getStringAttribute("PER_ORG");         
    strAction = object.getStringAttribute("ACTION");  
    strActionReason = object.getStringAttribute("ACTION_REASON"); 
    strEffectiveDate = object.getStringAttribute("EFFDT");
    strManager = object.getStringAttribute("SUPERVISOR_ID");
	strEmplClass = object.getStringAttribute("EMPL_CLASS");
    strSetIdLocation = object.getStringAttribute("SETID_LOCATION");


    if(strUsrName == null){

      logger.debug("Ascension-Rule-PrimaryDb-Customization-Rule::Record skipped as strUsrName= "+strUsrName);
      return null;

    }
    else{ 
      if(strAction!=null  && strPerOrg!=null && strActionReason!=null){
		  
		  if((strSetIdLocation !=null && strSetIdLocation.equalsIgnoreCase(ministryKey)) && (strPerOrg!=null && strPerOrg.equalsIgnoreCase("CWR"))){
          // Check if the 'cust' object and its attributes are not null
          Custom customObject = context.getObjectByName(Custom.class, custObjName);
          if (customObject != null) {
            exclusion = checkExclusion(customObject, ministryKey, strEmplClass);
            debug(logName,"Exclusion is : "+exclusion);
          }

          if(exclusion){

            return null;

          }

        }
		
        if(strAction.equalsIgnoreCase("ADD") || strAction.equalsIgnoreCase("REH") || strAction.equalsIgnoreCase("HIR")){

          SimpleDateFormat sdf = new SimpleDateFormat("MM/dd/yyyy");  
          String dateCheck=CheckDate(strEffectiveDate,sdf.format(new Date()));
          logger.debug("dateCheck is:::"+dateCheck);

          strCurrentDate = sdf.format(new Date());
          currentDate = sdf.parse(strCurrentDate);
          if(strEffectiveDate != null){

            effectiveDate = sdf.parse(strEffectiveDate);            
          }

          if(effectiveDate!=null){

            dayDifference=effectiveDate.getTime()-currentDate.getTime();
            dayDiff=dayDifference / 1000 / 60 / 60 / 24;
            logger.debug("days diff is:::"+dayDiff);
          } 

          if(dateCheck.equalsIgnoreCase("futureDate") ){ //|| dateCheck.equalsIgnoreCase("currentDate")

            qryOpt=new QueryOptions();
            Filter f1=Filter.or(Filter.eq("name",strUsrName),Filter.eq("employeeId",strUsrName));
            qryOpt.addFilter(f1);
            Iterator iterator = context.search(Identity.class,qryOpt);  

            if(iterator != null && iterator.hasNext()){
              Identity identity = iterator.next(); 
              if(identity!=null){

                strType=identity.getAttribute("type");

                if(!(identity.isInactive()) && dateCheck.equalsIgnoreCase("futureDate") ){ // active user
                  
                  if(dayDiff<=3 && (strType!=null && strType.equalsIgnoreCase("Contractor")) && (strPerOrg!=null && strPerOrg.equalsIgnoreCase("EMP"))){
                    logger.debug("user is active EMP or physiscian,aggregated before thier effDt");  
                  }else{
                    logger.debug("record is skipped as future dated typechange for active user");
                    return null;

                  }

                }
                if(identity.isInactive() ){ // inactive user
                  log.error("inactive user with future date "); 
                  if(strManager!=null){
                    qryOpt=new QueryOptions();
                    Filter f1=Filter.or(Filter.eq("name",strManager),Filter.eq("employeeId",strManager));
                    qryOpt.addFilter(f1);
                    Iterator iterator = context.search(Identity.class,qryOpt);  

                    if(iterator != null && iterator.hasNext()){
                      Identity manIdentity = iterator.next(); 
                      if(manIdentity!=null){
                        identity.setManager(manIdentity);
                      }
                    }
                  }
                  identity.setAttribute("inactive","false");


                  object.put("IIQDisabled", false);
                  object.put("inactive", false); 
                  context.saveObject(identity);
                  context.commitTransaction();


                }

              }  

            }  

          }
        }
      }
    }


  }catch(Exception e){

    log.error("Ascension-Rule-PrimaryDb-Customization-Rule::Exception= "+e.printStackTrace());
    throw e;      
  }    
  object.put("EMPLID",strUsrName);	
  logger.debug("Inside Ascension-Rule-PrimaryDb-Customization-Rule - STOP");
  return object;
